import * as React from 'react';
import { graphql, navigate } from 'gatsby';
import { GatsbyImage, getImage } from 'gatsby-plugin-image';
import Box from '@mui/material/Box';
import Grid from '@mui/material/Grid';
import Typography from '@mui/material/Typography';
import { Layout } from '../../components/layout';
import { Link } from '../../components/common/link';
import { Seo } from '../../components/seo';
import { Navigation } from '../../components/navigation';
import { idToLabel } from '../../libs/categories';
import { works } from '../../libs/works';

export default function WorksTemplate(props) {
  const [category, setCategory] = React.useState();

  const { data, params } = props;
  const slug = params.frontmatter__slug;

  const { markdownRemark } = data; // data.markdownRemark holds your post data
  const { html } = markdownRemark;

  const images = data.allFile.edges
    .filter(edge => {
      const result = edge.node.name.match(
        // /^portfolio_works_(\d{8}_.+)_(\d{2})$/
        /^portfolio_works_(\d{8}_.+)_(\d{2})/
      );

      if (!result || !result[1] || !result[2]) return false;

      // thumbnail
      if (result[2] === '00') return false;

      const name = result[1].replace(/_/g, '-');

      return name === slug;
    })
    .map(({ node }) => getImage(node));

  const _works = works.filter(work => {
    if (category) {
      return work.category === category;
    } else {
      return true;
    }
  });

  const currentIndex = _works.findIndex(({ link }) => link === slug);
  const nextIndex = (currentIndex + 1) % _works.length;
  const prevIndex = currentIndex === 0 ? _works.length - 1 : currentIndex - 1;

  const currentData = _works[currentIndex];
  const nextData = _works[nextIndex];
  const prevData = _works[prevIndex];

  const prevLink = `/works/${prevData?.link}/${
    category ? `?category=${category}` : ''
  }`;
  const nextLink = `/works/${nextData?.link}/${
    category ? `?category=${category}` : ''
  }`;
  const categoryLink = '/works/' + (category ? `?category=${category}` : '');

  React.useEffect(() => {
    const param = new URLSearchParams(props.location.search);
    setCategory(param.get('category'));
  }, [props.location.search]);

  return (
    <Layout>
      <Navigation />
      <Box py={10}>
        <Grid container justifyContent='center' spacing={4}>
          {images.map((image, i) => {
            const isPortrait = image.width <= image.height;
            const floatWidth = isPortrait ? '50%' : '75%';

            return (
              <Grid item xs={12} key={i}>
                <Box
                  sx={{
                    width: {
                      sm: floatWidth,
                      xs: '100%'
                    },
                    mx: 'auto',
                    pointerEvents: 'none',
                    userSelect: 'none'
                  }}
                  onClick={e => e.preventDefault()}
                  onMouseDown={e => e.preventDefault()}
                  onMouseUp={e => e.preventDefault()}
                  onContextMenu={e => {
                    e.preventDefault();
                  }}
                >
                  <GatsbyImage
                    image={image}
                    alt={`image-${i}`}
                    style={{
                      pointerEvents: 'none',
                      userSelect: 'none'
                    }}
                  />
                </Box>
              </Grid>
            );
          })}

          <Grid item xs={12} mb={4}>
            <div dangerouslySetInnerHTML={{ __html: html }} />
            <Typography sx={{ letterSpacing: '0.25rem', textAlign: 'center' }}>
              {currentData?.title}
            </Typography>
            <Typography sx={{ mt: 2, textAlign: 'center' }}>
              {currentData?.description}
            </Typography>
          </Grid>

          <Grid item xs={6}>
            <Box>
              <Link
                href={prevLink}
                onClick={e => {
                  e.preventDefault();
                  navigate(prevLink);
                }}
                sx={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'start'
                }}
              >
                &lt;
                <Typography
                  variant='body2'
                  align='left'
                  sx={{
                    ml: 1,
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    whiteSpace: 'nowrap'
                  }}
                >
                  {prevData?.title}
                </Typography>
              </Link>
            </Box>
          </Grid>
          <Grid item xs={6}>
            <Box>
              <Link
                href={nextLink}
                onClick={e => {
                  e.preventDefault();
                  navigate(nextLink);
                }}
                sx={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'end'
                }}
              >
                <Typography
                  variant='body2'
                  align='right'
                  sx={{
                    mr: 1,
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    whiteSpace: 'nowrap'
                  }}
                >
                  {nextData?.title}
                </Typography>
                &gt;
              </Link>
            </Box>
          </Grid>

          <Grid item xs={12}>
            <Box
              sx={{
                display: 'flex',
                justifyContent: 'center'
              }}
            >
              <Link
                href={categoryLink}
                onClick={e => {
                  e.preventDefault();
                  navigate(categoryLink);
                }}
              >
                <Typography variant='body2'>
                  Back to "{category ? idToLabel(category) : 'All'}"
                </Typography>
              </Link>
            </Box>
          </Grid>
        </Grid>
      </Box>
    </Layout>
  );
}

export const query = graphql`
  query ($id: String!) {
    markdownRemark(id: { eq: $id }) {
      html
      frontmatter {
        slug
      }
    }
    allFile(
      sort: { relativePath: ASC }
      filter: { relativeDirectory: { eq: "works" } }
    ) {
      edges {
        node {
          relativeDirectory
          childImageSharp {
            gatsbyImageData(width: 1920)
          }
          name
        }
      }
    }
  }
`;

export const Head = ({ params }) => {
  const slug = params.frontmatter__slug;

  const currentIndex = works.findIndex(({ link }) => link === slug);

  const title = works[currentIndex]?.title || '';

  return <Seo title={title} />;
};
